syntax:
# Basic function
def function_name(param1, param2):
    # code
    return value

# Default parameter
def greet(name, msg='Hello'):
    return f'{msg}, {name}!'

# *args - variable positional arguments
def add_all(*numbers):
    return sum(numbers)

# **kwargs - variable keyword arguments
def profile(**info):
    for k, v in info.items():
        print(f'{k}: {v}')

# Type hints (Python 3.5+)
def add(a: int, b: int) -> int:
    return a + b

