def name(params):
    # body
    return value  # optional

# Multiple return values
def stats(lst):
    return min(lst), max(lst), sum(lst)/len(lst)

lo, hi, avg = stats([1,2,3,4,5])

def recursive_func(n):
    # 1. BASE CASE (MUST HAVE!)
    if n == 0:
        return 0

    # 2. RECURSIVE CASE
    # Call with SMALLER input
    return n + recursive_func(n - 1)

# Each call reduces n by 1
# Eventually hits base case n==0
